#include <algorithm>

using namespace std;

string toHex(long long num) {
    if (num == 0) return "0";
    string hex;
    while (num > 0) {
        int rem = num % 16;
        if (rem < 10) {
            hex += '0' + rem;
        } else {
            hex += 'A' + (rem - 10);
        }
        num /= 16;
    }
    reverse(hex.begin(), hex.end());
    return hex;
}

string to36(long long num) {
    if (num == 0) return "0";
    string res;
    while (num > 0) {
        int rem = num % 36;
        if (rem < 10) {
            res += '0' + rem;
        } else {
            res += 'A' + (rem - 10);
        }
        num /= 36;
    }
    reverse(res.begin(), res.end());
    return res;
}

string solve(long long n) {
    long long n2 = n * n;
    long long n3 = n * n * n;
    string hex = toHex(n2);
    string thirtySix = to36(n3);
    return hex + thirtySix;
}

